// enum型の定義
public enum Season {
    SPRING, SUMMER, AUTUMN, WINTER
}

// 使い方
public class Main {
    public static void main(String[] args) {
        Season s = Season.SPRING;
        System.out.println(s);          // SPRING
        System.out.println(s.name());   // SPRING
        System.out.println(s.ordinal());// 0（定義順のインデックス）

        // values() — 全列挙定数の配列
        for (Season season : Season.values()) {
            System.out.println(season);
        }

        // valueOf() — 文字列から変換
        Season w = Season.valueOf("WINTER");
        System.out.println(w); // WINTER
        // Season.valueOf("spring"); → IllegalArgumentException
    }
}

// Mainクラスの定義
public class Main {
    // mainメソッドの定義
    public static void main(String[] args) {
        Season s = Season.AUTUMN;

        // switch文：caseにはenum定数名のみ（型名不要）
        // 値に応じた分岐処理
        switch (s) {
            case SPRING:
                System.out.println("春");
                break;
            case SUMMER:
                System.out.println("夏");
                break;
            case AUTUMN:
                System.out.println("秋");
                break;
            case WINTER:
                System.out.println("冬");
                break;
        }
        // 出力: 秋

        // ==で比較（推奨）
        // 条件分岐
        if (s == Season.AUTUMN) {
            System.out.println("紅葉の季節");
        }
    }
}

