// Mainクラスの定義
public class Main {
    // mainメソッドの定義
    public static void main(String[] args) {
        // 変数の宣言と初期化
        int day = 3;

        // 従来のswitch文
        String name1;
        // 値に応じた分岐処理
        switch (day) {
            case 1: name1 = "月"; break;
            case 2: name1 = "火"; break;
            case 3: name1 = "水"; break;
            default: name1 = "？"; break;
        }

        // Java 14+ switch式（アロー構文）
        // switchメソッドの定義
        String name2 = switch (day) {
            case 1 -> "月";
            case 2 -> "火";
            case 3 -> "水";
            default -> "？";
        };
        // ↑ switch式はセミコロンが必要

        System.out.println(name2); // 水

        // 複数のcase値をカンマで列挙
        String type = switch (day) {
            case 1, 2, 3, 4, 5 -> "平日";
            case 6, 7 -> "休日";
            default -> "不正";
        };
    }
}

// Mainクラスの定義
public class Main {
    // mainメソッドの定義
    public static void main(String[] args) {
        // 変数の宣言と初期化
        int score = 85;

        // ブロック構文 + yield
        // switchメソッドの定義
        String grade = switch (score / 10) {
            case 10, 9 -> "A";
            case 8 -> {
                System.out.println("Good!");
                yield "B";  // ブロック内ではyieldで値を返す
            }
            case 7 -> "C";
            default -> {
                yield "D";
            }
        };
        // 出力: Good!
        System.out.println(grade); // B

        // 注意: アロー構文でreturnは使えない（yieldを使う）
        // case 8 -> { return "B"; } // コンパイルエラー
    }
}

public class Main {
    // 従来のinstanceof + キャスト
    static void oldStyle(Object obj) {
        if (obj instanceof String) {
            String s = (String) obj;  // 明示的キャスト必要
            System.out.println(s.length());
        }
    }

    // Java 16+ パターンマッチング
    static void newStyle(Object obj) {
        if (obj instanceof String s) {  // 型チェック + 変数束縛
            System.out.println(s.length()); // sはString型として使える
        }

        // &&との組合せ（スコープに注意）
        if (obj instanceof String s && s.length() > 3) {
            System.out.println("長い文字列: " + s);
        }

        // || では使えない（コンパイルエラー）
        // if (obj instanceof String s || s.isEmpty()) { } // NG
    }

    // パターン変数のスコープ
    static void scopeExample(Object obj) {
        if (!(obj instanceof String s)) {
            return; // ここではsは使えない
        }
        // ここではsが使える（フロースコーピング）
        System.out.println(s.toUpperCase());
    }
}

